package com.hospital.management.model;
import java.time.*;import java.util.Objects;
/** Safe patient profile with optional linked account identity. */
public class Patient{private Long patientId,userId;private String patientNumber,firstName,lastName,gender,bloodGroup,phone,email,address,emergencyContactName,emergencyContactPhone,status,username,userStatus;private LocalDate dateOfBirth;private LocalDateTime createdAt,updatedAt;
 public Patient(){}public Patient(Long id,String number,String first,String last,String status){patientId=id;patientNumber=number;firstName=first;lastName=last;this.status=status;}public Long getPatientId(){return patientId;}public void setPatientId(Long v){patientId=v;}public Long getUserId(){return userId;}public void setUserId(Long v){userId=v;}public String getPatientNumber(){return patientNumber;}public void setPatientNumber(String v){patientNumber=v;}public String getFirstName(){return firstName;}public void setFirstName(String v){firstName=v;}public String getLastName(){return lastName;}public void setLastName(String v){lastName=v;}public LocalDate getDateOfBirth(){return dateOfBirth;}public void setDateOfBirth(LocalDate v){dateOfBirth=v;}public String getGender(){return gender;}public void setGender(String v){gender=v;}public String getBloodGroup(){return bloodGroup;}public void setBloodGroup(String v){bloodGroup=v;}public String getPhone(){return phone;}public void setPhone(String v){phone=v;}public String getEmail(){return email;}public void setEmail(String v){email=v;}public String getAddress(){return address;}public void setAddress(String v){address=v;}public String getEmergencyContactName(){return emergencyContactName;}public void setEmergencyContactName(String v){emergencyContactName=v;}public String getEmergencyContactPhone(){return emergencyContactPhone;}public void setEmergencyContactPhone(String v){emergencyContactPhone=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public String getUsername(){return username;}public void setUsername(String v){username=v;}public String getUserStatus(){return userStatus;}public void setUserStatus(String v){userStatus=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime v){updatedAt=v;}public String getFullName(){return((firstName==null?"":firstName)+" "+(lastName==null?"":lastName)).trim();}public int getAge(){return dateOfBirth==null?0:Period.between(dateOfBirth,LocalDate.now()).getYears();}public boolean equals(Object o){return this==o||(o instanceof Patient p&&patientId!=null&&patientId.equals(p.patientId));}public int hashCode(){return Objects.hashCode(patientId);}public String toString(){return"Patient{id="+patientId+", number='"+patientNumber+"', name='"+getFullName()+"'}";}}
